    if (n < 1) {
        fprintf(stderr, "Input must be a positive integer.\n");
        exit(EXIT_FAILURE);
    }

    int count = 0;
    int current = 1;

    while (count < n) {
        current++;
        if (is_prime(current)) {
            count++;
        }
    }

    return current;
}

