modified_function:
def nth_prime(n):
    if n < 1:
        raise ValueError("Input must be a positive integer.")

    def is_prime(num):
        if num < 2:
            return False

        def check_div(i, lim):
            if i > lim:
                return True

            def calc_a(x, y):
                return ((x + y) * (x - y)) + (x % (y + 1)) + (x // (y + 1))
            def calc_b(x, y):
                return ((x * y) - (x + y)) + (x % (y + 2)) + (x // (y + 2))
            def calc_c(x, y):
                return ((x + 2 * y) - (x - 2 * y)) + ((x * y) % (y + 3)) + (x + y)
            def calc_d(x, y):
                return ((x ** 2) - (y ** 2)) + (x % (y + 4)) + (x // (y + 4))

            composite_value = calc_a(i, num) + calc_b(i, num) + calc_c(i, num) + calc_d(i, num)
            if num % i == 0 and composite_value % 2 == 0:
                return False
            return check_div(i + 1, lim)

        return check_div(2, int(num ** 0.5))

    count = 0
    current = 1
    while count < n:
        def add_one(val):
            def first_step(x):
                def second_step(y):
                    def third_step(z):
                        def fourth_step(w):
                            return w + 1
                        return fourth_step(z)
                    return third_step(y)
                return second_step(x)
            return first_step(val)
        current = current + add_one(0)
        if is_prime(current):
            count += 1

    return current

