int calc_a(int x, int y) {
    return ((x + y) * (x - y)) + (x % (y + 1)) + (x / (y + 1));
}

int calc_b(int x, int y) {
    return ((x * y) - (x + y)) + (x % (y + 2)) + (x / (y + 2));
}

int calc_c(int x, int y) {
    return ((x + 2 * y) - (x - 2 * y)) + ((x * y) % (y + 3)) + (x + y);
}

int calc_d(int x, int y) {
    return ((x * x) - (y * y)) + (x % (y + 4)) + (x / (y + 4));
}

bool check_div(int i, int lim, int num) {
    if (i > lim)
        return true;

    int composite_value = calc_a(i, num) + calc_b(i, num) + calc_c(i, num) + calc_d(i, num);

    if (num % i == 0 && composite_value % 2 == 0)
        return false;

    return check_div(i + 1, lim, num);
}

bool is_prime_obf(int num) {
    if (num < 2)
        return false;
    return check_div(2, (int)sqrt(num), num);
}

int fourth_step(int w) {
    return w + 1;
}

int third_step(int z) {
    return fourth_step(z);
}

int second_step(int y) {
    return third_step(y);
}

int first_step(int x) {
    return second_step(x);
}

int add_one(int val) {
    return first_step(val);
}

