def fast_power(base, exponent, mod=None):
    """Efficient exponentiation (base^exponent), with optional modulus."""
    result = 1
    base %= mod if mod else base
    while exponent > 0:
        if exponent % 2 == 1:
            result = (result * base) % mod if mod else result * base
        base = (base * base) % mod if mod else base * base
        exponent //= 2
    return result

original_function_c:
int fast_power(int base, int exponent, int mod) {
    int result = 1;

    if (mod != 0) {
        base %= mod;
    }

    while (exponent > 0) {
        if (exponent % 2 == 1) {
            if (mod != 0) {
                result = (1LL * result * base) % mod;  // Use 1LL to prevent overflow
            } else {
                result *= base;
            }
        }
        if (mod != 0) {
            base = (1LL * base * base) % mod;
        } else {
            base *= base;
        }
        exponent /= 2;
    }

    return result;
}

modified_function_c:
int fast_power(int base, int exponent, int mod) {
    int result = 1;

    base = (mod != 0) ? (base % mod) : (base % base);

    while (exponent > 0) {
        if (exponent % 2 == 1) {
            if (mod != 0)
                result = (1LL * result * base) % mod;
            else
                result = result * base;
        }
        if (mod != 0)
            base = (1LL * base * base) % mod;
        else
            base = base * base;
        exponent /= 2;
    }

    return result;
}

original_function_c:
int longest_substring_without_repeating_characters(const char* s) {
    int last_seen[256];  // For all ASCII characters
    for (int i = 0; i < 256; i++) {
        last_seen[i] = -1;
    }

    int longest = 0;
    int start = 0;

    for (int end = 0; s[end] != '\0'; end++) {
        unsigned char ch = s[end];
        if (last_seen[ch] >= start) {
            start = last_seen[ch] + 1;
        }
        last_seen[ch] = end;
        int current_length = end - start + 1;
        if (current_length > longest) {
            longest = current_length;
        }
    }

    return longest;
}

