int** allocate_matrix(int size) {
    int** matrix = malloc(size * sizeof(int*));
    for (int i = 0; i < size; i++)
        matrix[i] = calloc(size, sizeof(int));
    return matrix;
}

void free_matrix(int** matrix, int size) {
    for (int i = 0; i < size; i++)
        free(matrix[i]);
    free(matrix);
}

void add_matrix(int** A, int** B, int** C, int size) {
    for (int i = 0; i < size; i++)
        for (int j = 0; j < size; j++)
            C[i][j] = A[i][j] + B[i][j];
}

void subtract_matrix(int** A, int** B, int** C, int size) {
    for (int i = 0; i < size; i++)
        for (int j = 0; j < size; j++)
            C[i][j] = A[i][j] - B[i][j];
}

void copy_submatrix(int** src, int** dest, int row, int col, int size) {
    for (int i = 0; i < size; i++)
        for (int j = 0; j < size; j++)
            dest[i][j] = src[i + row][j + col];
}

void insert_submatrix(int** dest, int** src, int row, int col, int size) {
    for (int i = 0; i < size; i++)
        for (int j = 0; j < size; j++)
            dest[i + row][j + col] = src[i][j];
}

int** strassen_matrix_multiplication(int** A, int** B, int size) {
    if (size == 1) {
        int** C = allocate_matrix(1);
        C[0][0] = A[0][0] * B[0][0];
        return C;
    }

    int newSize = size / 2;

    int** A11 = allocate_matrix(newSize);
    int** A12 = allocate_matrix(newSize);
    int** A21 = allocate_matrix(newSize);
    int** A22 = allocate_matrix(newSize);
    int** B11 = allocate_matrix(newSize);
    int** B12 = allocate_matrix(newSize);
    int** B21 = allocate_matrix(newSize);
    int** B22 = allocate_matrix(newSize);

    copy_submatrix(A, A11, 0, 0, newSize);
    copy_submatrix(A, A12, 0, newSize, newSize);
    copy_submatrix(A, A21, newSize, 0, newSize);
    copy_submatrix(A, A22, newSize, newSize, newSize);

    copy_submatrix(B, B11, 0, 0, newSize);
    copy_submatrix(B, B12, 0, newSize, newSize);
    copy_submatrix(B, B21, newSize, 0, newSize);
    copy_submatrix(B, B22, newSize, newSize, newSize);

    // M1 = (A11 + A22) * (B11 + B22)
    int** T1 = allocate_matrix(newSize);
    int** T2 = allocate_matrix(newSize);
    add_matrix(A11, A22, T1, newSize);
    add_matrix(B11, B22, T2, newSize);
    int** M1 = strassen_matrix_multiplication(T1, T2, newSize);
    free_matrix(T1, newSize); free_matrix(T2, newSize);

    // M2 = (A21 + A22) * B11
    T1 = allocate_matrix(newSize);
    add_matrix(A21, A22, T1, newSize);
    int** M2 = strassen_matrix_multiplication(T1, B11, newSize);
    free_matrix(T1, newSize);

    // M3 = A11 * (B12 - B22)
    T1 = allocate_matrix(newSize);
    subtract_matrix(B12, B22, T1, newSize);
    int** M3 = strassen_matrix_multiplication(A11, T1, newSize);
    free_matrix(T1, newSize);

    // M4 = A22 * (B21 - B11)
    T1 = allocate_matrix(newSize);
    subtract_matrix(B21, B11, T1, newSize);
    int** M4 = strassen_matrix_multiplication(A22, T1, newSize);
    free_matrix(T1, newSize);

    // M5 = (A11 + A12) * B22
    T1 = allocate_matrix(newSize);
    add_matrix(A11, A12, T1, newSize);
    int** M5 = strassen_matrix_multiplication(T1, B22, newSize);
    free_matrix(T1, newSize);

    // M6 = (A21 - A11) * (B11 + B12)
    T1 = allocate_matrix(newSize);
    T2 = allocate_matrix(newSize);
    subtract_matrix(A21, A11, T1, newSize);
    add_matrix(B11, B12, T2, newSize);
    int** M6 = strassen_matrix_multiplication(T1, T2, newSize);
    free_matrix(T1, newSize); free_matrix(T2, newSize);

    // M7 = (A12 - A22) * (B21 + B22)
    T1 = allocate_matrix(newSize);
    T2 = allocate_matrix(newSize);
    subtract_matrix(A12, A22, T1, newSize);
    add_matrix(B21, B22, T2, newSize);
    int** M7 = strassen_matrix_multiplication(T1, T2, newSize);
    free_matrix(T1, newSize); free_matrix(T2, newSize);

    // C11 = M1 + M4 - M5 + M7
    int** C11 = allocate_matrix(newSize);
    T1 = allocate_matrix(newSize);
    T2 = allocate_matrix(newSize);
    add_matrix(M1, M4, T1, newSize);
    subtract_matrix(T1, M5, T2, newSize);
    add_matrix(T2, M7, C11, newSize);
    free_matrix(T1, newSize); free_matrix(T2, newSize);

    // C12 = M3 + M5
    int** C12 = allocate_matrix(newSize);
    add_matrix(M3, M5, C12, newSize);

    // C21 = M2 + M4
    int** C21 = allocate_matrix(newSize);
    add_matrix(M2, M4, C21, newSize);

    // C22 = M1 + M3 - M2 + M6
    int** C22 = allocate_matrix(newSize);
    T1 = allocate_matrix(newSize);
    T2 = allocate_matrix(newSize);
    add_matrix(M1, M3, T1, newSize);
    subtract_matrix(T1, M2, T2, newSize);
    add_matrix(T2, M6, C22, newSize);
    free_matrix(T1, newSize); free_matrix(T2, newSize);

    int** C = allocate_matrix(size);
    insert_submatrix(C, C11, 0, 0, newSize);
    insert_submatrix(C, C12, 0, newSize, newSize);
    insert_submatrix(C, C21, newSize, 0, newSize);
    insert_submatrix(C, C22, newSize, newSize, newSize);

    free_matrix(A11, newSize); free_matrix(A12, newSize); free_matrix(A21, newSize); free_matrix(A22, newSize);
    free_matrix(B11, newSize); free_matrix(B12, newSize); free_matrix(B21, newSize); free_matrix(B22, newSize);
    free_matrix(C11, newSize); free_matrix(C12, newSize); free_matrix(C21, newSize); free_matrix(C22, newSize);
    free_matrix(M1, newSize); free_matrix(M2, newSize); free_matrix(M3, newSize); free_matrix(M4, newSize);
    free_matrix(M5, newSize); free_matrix(M6, newSize); free_matrix(M7, newSize);

    return C;
}

