int** allocate_matrix_rc(int rows, int cols) {
    int** matrix = malloc(rows * sizeof(int*));
    for (int i = 0; i < rows; i++)
        matrix[i] = calloc(cols, sizeof(int));
    return matrix;
}

void _flood_fill_recursive(int** matrix, int rows, int cols, int x, int y, int original_color, int new_color) {
    if (x < 0 || x >= rows || y < 0 || y >= cols)
        return;
    if (matrix[x][y] != original_color)
        return;

    matrix[x][y] = new_color;

    _flood_fill_recursive(matrix, rows, cols, x + 1, y, original_color, new_color);
    _flood_fill_recursive(matrix, rows, cols, x - 1, y, original_color, new_color);
    _flood_fill_recursive(matrix, rows, cols, x, y + 1, original_color, new_color);
    _flood_fill_recursive(matrix, rows, cols, x, y - 1, original_color, new_color);
}

void flood_fill(int** matrix, int rows, int cols, int x, int y, int new_color) {
    int original_color = matrix[x][y];
    if (original_color == new_color)
        return;

    _flood_fill_recursive(matrix, rows, cols, x, y, original_color, new_color);
}

