// Postorder traversal: Left, Right, Root
void binary_tree_postorder_traversal(TreeNode* root, int* output, int* index) {
    if (root == NULL) return;
    binary_tree_postorder_traversal(root->left, output, index);
    binary_tree_postorder_traversal(root->right, output, index);
    output[(*index)++] = root->val;
}

