original_function_c:
int int_pow10(int exp) {
    int result = 1;
    while (exp-- > 0) result *= 10;
    return result;
}

int karatsuba(int x, int y) {
    if (x < 10 || y < 10)
        return x * y;

    int len_x = (int)log10(x) + 1;
    int len_y = (int)log10(y) + 1;
    int m = (len_x > len_y) ? len_x : len_y;
    int m2 = m / 2;

    int pow10_m2 = int_pow10(m2);

    int high1 = x / pow10_m2;
    int low1  = x % pow10_m2;
    int high2 = y / pow10_m2;
    int low2  = y % pow10_m2;

    int z0 = karatsuba(low1, low2);
    int z1 = karatsuba(low1 + high1, low2 + high2);
    int z2 = karatsuba(high1, high2);

    return (z2 * int_pow10(2 * m2)) + ((z1 - z2 - z0) * pow10_m2) + z0;
}

