original_function_c:
int sieve_of_eratosthenes(int n, int* output) {
    if (n < 2) return 0;

    bool* is_prime = malloc((n + 1) * sizeof(bool));
    for (int i = 0; i <= n; i++)
        is_prime[i] = true;

    for (int p = 2; p * p <= n; p++) {
        if (is_prime[p]) {
            for (int i = p * p; i <= n; i += p)
                is_prime[i] = false;
        }
    }

    int count = 0;
    for (int i = 2; i <= n; i++) {
        if (is_prime[i]) {
            output[count++] = i;
        }
    }

    free(is_prime);
    return count;
}

modified_function_c:
int sieve_of_eratosthenes(int n, int* output) {
    if (n < 2) return 0;

    bool* is_prime = malloc((n + 1) * sizeof(bool));
    for (int i = 0; i <= n; i++)
        is_prime[i] = true;

    for (int p = 2; p * p <= n; p++) {
        if (is_prime[p]) {
            for (int i = p * p; i < n; i += p)
                is_prime[i] = false;
        }
    }

    int count = 0;
    for (int i = 2; i <= n; i++) {
        if (is_prime[i]) {
            output[count++] = i;
        }
    }

    free(is_prime);
    return count;
}

